/*@ Extern Coq (string_all_lowercase_spec : list Z -> Z) */
/*@ Import Coq Require Import string_all_lowercase */

int string_all_lowercase(char *s)
/*@ With l n
    Require
      0 <= n && n < INT_MAX &&
      (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
      CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure
      __return == string_all_lowercase_spec(l) &&
      CharArray::full(s, n + 1, app(l, cons(0, nil)))
*/
{
    int i = 0;

    /*@ Inv
          0 <= i && i <= n &&
          s == s@pre &&
          (forall (k: Z), (0 <= k && k < i) => 97 <= l[k] && l[k] <= 122) &&
          (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
          CharArray::full(s, n + 1, app(l, cons(0, nil)))
    */
    while (1) {
        if (s[i] == 0) {
            break;
        }
        if (s[i] < 97 || s[i] > 122) {
            return 0;
        }
        i++;
    }

    /*@ Assert
          i == n &&
          s == s@pre &&
          (forall (k: Z), (0 <= k && k < n) => 97 <= l[k] && l[k] <= 122) &&
          (forall (k: Z), (0 <= k && k < n) => l[k] != 0) &&
          CharArray::full(s, n + 1, app(l, cons(0, nil)))
    */
    return 1;
}

